import React, { useState } from 'react';

const Tasks = () => {
  const [tasks, setTasks] = useState([]);
  const [input, setInput] = useState('');
  
  const handleAddTask = () => {
    if (input.trim() === '') return;
    setTasks([...tasks, { title: input, subtasks: [], showEdit: false, subInput: '' }]);
    setInput('');
  };

  const handleDelete = (index) => {
    const updated = [...tasks];
    updated.splice(index, 1);
    setTasks(updated);
  };

  const handleEditToggle = (index) => {
    const updated = [...tasks];
    updated[index].showEdit = !updated[index].showEdit;
    setTasks(updated);
  };

  const handleTitleChange = (index, newTitle) => {
    const updated = [...tasks];
    updated[index].title = newTitle;
    setTasks(updated);
  };

  const handleSubInputChange = (index, value) => {
    const updated = [...tasks];
    updated[index].subInput = value;
    setTasks(updated);
  };

  const handleAddSubtask = (index) => {
    const updated = [...tasks];
    const task = updated[index];
    if (task.subInput.trim() !== '') {
      task.subtasks.push({ text: task.subInput, checked: false });
      task.subInput = '';
      setTasks(updated);
    }
  };

  const handleSubCheck = (taskIndex, subIndex) => {
    const updated = [...tasks];
    updated[taskIndex].subtasks[subIndex].checked = !updated[taskIndex].subtasks[subIndex].checked;
    setTasks(updated);
  };

  return (
    <div className="page-container">
      <div className="task-input-row">
        <input 
          className="task-input" 
          placeholder="Add Task ...." 
          value={input} 
          onChange={(e) => setInput(e.target.value)} 
        />
        <button className="add-btn" onClick={handleAddTask}>Add</button>
      </div>

      <div className="tasks-container">
        {tasks.map((task, i) => (
          <div key={i} className="task-box">
            {task.showEdit ? (
              <>
                <input 
                  className="edit-input"
                  value={task.title}
                  onChange={(e) => handleTitleChange(i, e.target.value)}
                />
                <div className="subtask-row">
                  <input 
                    className="sub-input"
                    placeholder="Add subtask..."
                    value={task.subInput}
                    onChange={(e) => handleSubInputChange(i, e.target.value)}
                  />
                  <button onClick={() => handleAddSubtask(i)}>➕</button>
                </div>
                <ul className="checkbox-list">
                  {task.subtasks.map((sub, j) => (
                    <li key={j}>
                      <label>
                        <input 
                          type="checkbox" 
                          checked={sub.checked}
                          onChange={() => handleSubCheck(i, j)} 
                        />
                        {sub.text}
                      </label>
                    </li>
                  ))}
                </ul>
              </>
            ) : (
              <>
                <h3>{task.title}</h3>
              </>
            )}

            <div className="task-actions">
              <button onClick={() => handleAddSubtask(i)}>➕</button>
              <button onClick={() => handleEditToggle(i)}>✏️</button>
              <button onClick={() => handleDelete(i)}>🗑️</button>
            </div>
          </div>
        ))}
      </div>
      <Stylesheet/>
    </div>
  );
};


const Stylesheet=()=>{
  return <style>{`
  :root {
  --text: #7e5f40;
  --bg-parchment: #f5e6c8;
  --secondary-color: #d6b98c;
  --button-border: #5a4432;
  --font-text: #4b3621;
  --text-light: #7a6651;
  --accent-lavender: #8c6fc3;
  --button-color: #7b8b58;
  --flower-white: #fdfaf5;
}

.task-page {
  padding: 2rem;
  font-family: 'Cedarville Cursive', cursive;
  background-image: url('/path/to/your/botanical-background.png');
  background-size: cover;
  background-position: center;
}

.task-input-row {
  display: flex;
  justify-content: center;
  gap: 1rem;
  margin-bottom: 2rem;
}

.task-input {
  padding: 1rem 1.5rem;
  font-size: 1.3rem;
  border: 2px solid var(--button-border);
  border-radius: 10px;
  width: 300px;
  background: var(--flower-white);
  color: var(--font-text);
  font-family: 'Cedarville Cursive', cursive;
}

.add-btn {
  padding: 0.8rem 1.5rem;
  background-color: var(--secondary-color);
  color: var(--font-text);
  border: 2px solid var(--button-border);
  border-radius: 10px;
  font-size: 1.2rem;
  cursor: pointer;
  font-family: 'Cedarville Cursive', cursive;
}

.task-cards {
  display: flex;
  justify-content: space-evenly;
  flex-wrap: wrap;
  gap: 2rem;
}

.task-card {
  background-color: var(--secondary-color);
  border: 2px solid var(--button-border);
  padding: 1rem;
  border-radius: 12px;
  width: 220px;
  color: var(--font-text);
}

.task-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.icons button {
  background: none;
  border: none;
  font-size: 1.1rem;
  margin-left: 5px;
  cursor: pointer;
  color: var(--font-text);
}

.task-title {
  font-size: 1.2rem;
  font-weight: bold;
}

.task-items {
  margin-top: 1rem;
  list-style: none;
  padding: 0;
}

.task-items li {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin: 0.3rem 0;
}

.checked {
  text-decoration: line-through;
  color: var(--text-light);
}
  
  `}</style>
}

export default Tasks;
